"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[9277],{7744:e=>{e.exports=JSON.parse('{"version":{"pluginId":"assets","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"assetsSidebar":[{"type":"category","label":"Targeted Assets","items":[{"type":"link","href":"/MariOT_Matrix/assets/remote_access_gateways","label":"Remote Access Gateways","docId":"remote_access_gateways","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/third-party_it_and_ot_support_systems","label":"Third-Party IT and OT Support Systems","docId":"third-party_it_and_ot_support_systems","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/vessel_management_systems","label":"Vessel Management Systems (VMS)","docId":"vessel_management_systems","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/supervisory_control_and_data_acquisition_systems","label":"Supervisory Control and Data Acquisition (SCADA) Systems","docId":"supervisory_control_and_data_acquisition_systems","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/enterprise_resource_planning_&_supply_chain_systems","label":"Enterprise Resource Planning (ERP) & Supply Chain Systems","docId":"enterprise_resource_planning_&_supply_chain_systems","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/automatic_identification_system","label":"Automatic Identification System (AIS)","docId":"automatic_identification_system","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/electronic_chart_display_and_information_system","label":"Electronic Chart Display and Information System (ECDIS)","docId":"electronic_chart_display_and_information_system","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/port_&_terminal_operating_systems","label":"Port & Terminal Operating Systems (TOS)","docId":"port_&_terminal_operating_systems","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/crew_and_administrative_systems","label":"Crew and Administrative Systems","docId":"crew_and_administrative_systems","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/maritime_distress_and_safety_system","label":"Maritime Distress and Safety System","docId":"maritime_distress_and_safety_system","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/shipboard_remote_maintenance_software","label":"Shipboard Remote Maintenance Software","docId":"shipboard_remote_maintenance_software","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/maritime_satellite_communications","label":"Maritime Satellite Communications","docId":"maritime_satellite_communications","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/integrated_communication_systems","label":"Integrated Communication Systems","docId":"integrated_communication_systems","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/power_management_systems","label":"Power Management Systems","docId":"power_management_systems","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/voyage_data_recorder","label":"Voyage Data Recorder","docId":"voyage_data_recorder","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/emergency_position_indication_radio_beacon","label":"Emergency Position Indication Radio Beacon ","docId":"emergency_position_indication_radio_beacon","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/vessel_performance_monitoring_system","label":"Vessel Performance Monitoring System ","docId":"vessel_performance_monitoring_system","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/port_management_information_system","label":"Port Management Information System ","docId":"port_management_information_system","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/cargo_loading_management_system","label":"Cargo Loading Management System","docId":"cargo_loading_management_system","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/global_positioning_system","label":"Global Positioning System","docId":"global_positioning_system","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/aid_to_navigation_system","label":"Aid to Navigation System","docId":"aid_to_navigation_system","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/radar_and_arpa_system","label":"Radar and Automatic Radar Plotting Aid","docId":"radar_and_arpa_system","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/vessel_traffic_services","label":" Vessel Traffic Services","docId":"vessel_traffic_services","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/ais_sart_and_mob","label":"AIS-SART and MOB-AIS Devices","docId":"ais_sart_and_mob","unlisted":false},{"type":"link","href":"/MariOT_Matrix/assets/opencpn_charting_software","label":"OpenCPN Charting Software","docId":"opencpn_charting_software","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"aid_to_navigation_system":{"id":"aid_to_navigation_system","title":"Aid to Navigation System","description":"Aid to Navigation (AtoN) systems are maritime infrastructures designed to support safe vessel navigation, particularly in coastal, harbor, and high-traffic areas. These include physical beacons, buoys, and virtual AtoNs (V-AtoNs), which are broadcasted via AIS without a physical counterpart.","sidebar":"assetsSidebar"},"ais_sart_and_mob":{"id":"ais_sart_and_mob","title":"AIS-SART and MOB-AIS Devices","description":"AIS-SART (Search and Rescue Transmitter) and MOB-AIS (Man Overboard Beacon) are emergency AIS-based transmitters used for SAR operations. They broadcast distress signals to nearby vessels and shore stations.","sidebar":"assetsSidebar"},"assets-overview":{"id":"assets-overview","title":"Assets Overview","description":"Assets represent the devices and systems commonly found within Industrial Control System (ICS) environments."},"automatic_identification_system":{"id":"automatic_identification_system","title":"Automatic Identification System (AIS)","description":"AIS is a shipborne broadcast system used for maritime traffic coordination, collision avoidance, and situational awareness. Due to its lack of authentication and encryption, AIS is vulnerable to spoofing, signal injection, and data manipulation\u2014posing safety and security risks for vessel operations and maritime domain awareness.","sidebar":"assetsSidebar"},"cargo_loading_management_system":{"id":"cargo_loading_management_system","title":"Cargo Loading Management System","description":"A Cargo Loading Management System is a shipboard OT system responsible for the safe planning, monitoring, and execution of cargo and ballast operations. It controls key functions such as tank level measurements, ballast water transfer, valve automation, and load distribution to ensure vessel stability and compliance with loading regulations. These systems often interface with Programmable Logic Controllers (PLCs), Human-Machine Interfaces (HMIs), and may be remotely accessed from shore-based terminals. Unauthorized access or logic manipulation could result in critical safety and stability risks during cargo operations.","sidebar":"assetsSidebar"},"crew_and_administrative_systems":{"id":"crew_and_administrative_systems","title":"Crew and Administrative Systems","description":"Crew and administrative systems handle sensitive HR data, payroll records, and access credentials for shipboard and shore-based personnel. Although not part of OT operations directly, these systems often store privileged accounts, VPN certificates, or directory credentials\u2014making them attractive initial targets for attackers seeking to compromise maritime IT/OT environments through lateral movement or credential harvesting.","sidebar":"assetsSidebar"},"electronic_chart_display_and_information_system":{"id":"electronic_chart_display_and_information_system","title":"Electronic Chart Display and Information System (ECDIS)","description":"ECDIS is a digital navigation system that integrates chart data, GPS, AIS, and sensor inputs to support real-time route planning and maritime situational awareness. Its central role in bridge operations makes it a high-value target\u2014if compromised, attackers could manipulate chart overlays or mislead navigators, leading to route deviations or grounding risks.","sidebar":"assetsSidebar"},"emergency_position_indication_radio_beacon":{"id":"emergency_position_indication_radio_beacon","title":"Emergency Position Indication Radio Beacon","description":"An Emergency Position Indicating Radio Beacon (EPIRB) is a distress signaling device used to transmit a ship\'s location in case of an emergency at sea. When activated, an EPIRB sends a distress signal via satellite (e.g., COSPAS-SARSAT) to search and rescue services, providing essential location information for rescue operations. EPIRBs are mandatory for most commercial vessels and significantly enhance maritime safety.","sidebar":"assetsSidebar"},"enterprise_resource_planning_&_supply_chain_systems":{"id":"enterprise_resource_planning_&_supply_chain_systems","title":"Enterprise Resource Planning (ERP) & Supply Chain Systems","description":"ERP and supply chain systems coordinate maritime logistics, procurement, and financial operations across fleet, port, and supplier networks. These centralized platforms are tightly integrated with operational processes and external vendors, making them attractive targets for attackers seeking to disrupt fuel deliveries, cargo operations, or introduce malicious code through compromised supply chains.","sidebar":"assetsSidebar"},"global_positioning_system":{"id":"global_positioning_system","title":"Global Positioning System","description":"The Global Positioning System (GPS) is a satellite-based navigation technology that provides real-time position, velocity, and time synchronization. In maritime Operational Technology (OT) environments, GPS is a foundational service enabling precise navigation and coordination of vessel operations. It supports a wide range of onboard systems such as the Automatic Identification System (AIS), Electronic Chart Display and Information System (ECDIS), Autopilot systems, and Vessel Traffic Services (VTS).","sidebar":"assetsSidebar"},"integrated_communication_systems":{"id":"integrated_communication_systems","title":"Integrated Communication Systems","description":"Integrated communication systems on vessels support both ship-to-shore and intra-vessel communications, including safety alerts, navigation coordination, and inter-crew signaling. These systems often rely on vendor-provided software or centralized control panels, which\u2014if misconfigured or vulnerable\u2014may be exploited to execute unauthorized code, disrupt emergency communications, or enable persistent remote access to maritime networks.","sidebar":"assetsSidebar"},"maritime_distress_and_safety_system":{"id":"maritime_distress_and_safety_system","title":"Maritime Distress and Safety System","description":"Maritime distress and safety systems (e.g., GMDSS) provide essential communication capabilities for emergency signaling, vessel tracking, and distress coordination. These systems are mission-critical for crew safety, yet often rely on remotely accessible infrastructure or predefined communication protocols\u2014making them potential targets for attackers seeking to suppress alerts, impersonate vessels, or exploit trusted communication channels.","sidebar":"assetsSidebar"},"maritime_satellite_communications":{"id":"maritime_satellite_communications","title":"Maritime Satellite Communications","description":"Maritime satellite communication systems (e.g., VSAT, Inmarsat, Iridium) provide essential ship-to-shore connectivity for navigation, operations, and remote maintenance. These networks often serve as trusted channels for remote access and telemetry, but may be vulnerable to credential abuse, signal hijacking, or misconfigured trust relationships\u2014making them critical pathways for potential OT intrusion.","sidebar":"assetsSidebar"},"opencpn_charting_software":{"id":"opencpn_charting_software","title":"OpenCPN Charting Software","description":"OpenCPN is an open source electronic charting and navigation software that is commonly used on conventionally equipped and autonomous vessels. It provides real-time situational awareness by processing maritime data from onboard sensors, including GPS, radar, and depth sounders. The system supports standard communication protocols such as AIS and National Marine Electronics Association (NMEA) 0183.","sidebar":"assetsSidebar"},"port_&_terminal_operating_systems":{"id":"port_&_terminal_operating_systems","title":"Port & Terminal Operating Systems (TOS)","description":"Port and Terminal Operating Systems (TOS) manage critical workflows across vessel arrival, berthing, cargo transfer, and customs clearance. These systems are often interconnected with shipping company platforms, customs APIs, and shore-based OT equipment\u2014making them attractive targets for attackers aiming to disrupt port logistics or exploit weak authentication for lateral movement.","sidebar":"assetsSidebar"},"port_management_information_system":{"id":"port_management_information_system","title":"Port Management Information System","description":"A Port Management Information System (PMIS) is an integrated software solution used by port authorities and terminal operators to manage port operations efficiently. It includes functionalities for vessel traffic management, cargo handling, berth scheduling, customs clearance, and logistics coordination. PMIS enhances operational efficiency, optimizes resource utilization, and supports real-time decision-making for port authorities and shipping companies.","sidebar":"assetsSidebar"},"power_management_systems":{"id":"power_management_systems","title":"Power Management Systems","description":"Power Management Systems control electrical distribution and automation aboard ships, ensuring stable power supply to key operational and safety systems. If compromised, attackers could inject startup execution mechanisms to manipulate or disable power automation, leading to potential blackouts, propulsion failures, or safety hazards.","sidebar":"assetsSidebar"},"radar_and_arpa_system":{"id":"radar_and_arpa_system","title":"Radar and Automatic Radar Plotting Aid","description":"Radar and ARPA systems are key shipboard sensors that provide real-time detection and tracking of other vessels and objects, often overlaid with AIS targets in integrated navigation displays.","sidebar":"assetsSidebar"},"remote_access_gateways":{"id":"remote_access_gateways","title":"Remote Access Gateways","description":"Remote Access Gateways\u2014typically IT-native interfaces like virtual private networks (VPN), SSH, Remote Desktop Protocol (RDP)\u2014are frequently used by third parties to maintain or troubleshoot OT systems on board vessels. This introduces cross-domain trust that can be abused if it is misconfigured or compromised.","sidebar":"assetsSidebar"},"shipboard_remote_maintenance_software":{"id":"shipboard_remote_maintenance_software","title":"Shipboard Remote Maintenance Software","description":"Shipboard remote maintenance software allows equipment vendors and service providers to perform diagnostics, configuration changes, and firmware updates over remote channels. These platforms often have deep access to OT assets and, if compromised, can serve as direct vectors to deploy malware, manipulate control logic, or bypass the security boundaries of ships.","sidebar":"assetsSidebar"},"supervisory_control_and_data_acquisition_systems":{"id":"supervisory_control_and_data_acquisition_systems","title":"Supervisory Control and Data Acquisition (SCADA) Systems","description":"SCADA systems in maritime environments provide remote supervision and control over onboard propulsion, engine performance, and automation. Due to their central role in vessel operations and frequent integration with shore-based support systems, they represent high-impact targets for attackers seeking to disrupt physical control processes or override safety-critical functions.","sidebar":"assetsSidebar"},"third-party_it_and_ot_support_systems":{"id":"third-party_it_and_ot_support_systems","title":"Third-Party IT and OT Support Systems","description":"Third-Party IT and OT Support Systems External service providers are essential for the maintenance of maritime IT and OT systems, offering remote access for monitoring, diagnostics and technical support. However, these trusted connections can become points of vulnerability; If compromised, adversaries could gain access to or disrupt critical systems onboard OT, including navigation, power management, and propulsion control.","sidebar":"assetsSidebar"},"vessel_management_systems":{"id":"vessel_management_systems","title":"Vessel Management Systems (VMS)","description":"Vessel Management Systems are integrated shipboard platforms that coordinate navigation, cargo handling, and vessel automation through a combination of IT and OT subsystems.These systems often interface with remote maintenance platforms or shore-based control centers, making them high-value targets for attackers seeking to disrupt maritime operations or gain privileged access to onboard control systems.","sidebar":"assetsSidebar"},"vessel_performance_monitoring_system":{"id":"vessel_performance_monitoring_system","title":"vessel_performance_monitoring_system","description":"A Vessel Performance Monitoring System is a digital system designed to track and analyze a ship\u2019s operational efficiency. It collects data from onboard sensors related to fuel consumption, engine performance, hull resistance, weather conditions, and route optimization. The system helps ship operators improve fuel efficiency, reduce emissions, and ensure compliance with regulatory standards such as IMO\u2019s Energy Efficiency Existing Ship Index (EEXI) and Carbon Intensity Indicator (CII).","sidebar":"assetsSidebar"},"vessel_traffic_services":{"id":"vessel_traffic_services","title":"Vessel Traffic Services","description":"VTS are shore-based systems that monitor and manage vessel movement in congested waters using radar, AIS, CCTV, and radio communication. VTS centers rely on AIS for traffic monitoring and incident response.","sidebar":"assetsSidebar"},"voyage_data_recorder":{"id":"voyage_data_recorder","title":"Voyage Data Recorder","description":"A Voyage Data Recorder (VDR) is a data recording system installed on ships, similar to a \\"black box\\" in aircraft. It continuously captures navigational, positional, and sensor data, including voice recordings from the bridge, radar images, AIS (Automatic Identification System) data, and communication logs. The primary purpose of a VDR is to aid in accident investigations, safety assessments, and performance monitoring.","sidebar":"assetsSidebar"}}}}')}}]);